      if (aliveCells.some(([cx, cy]) => cx === x + dx && cy === y + dy)) {
        count++;
      }
    }
  }
  return count;
};

export function nextGeneration(aliveCells: Array<[number, number]>): Array<[number, number]> {
  if (aliveCells.length < 3) {
    return [];
